SELECT

FROM coupon_activation_batch b
LEFT JOIN coupon_template t ON t.id = b.template_id AND t.is_deleted = 0

    b.is_deleted = 0

        AND b.batch_no LIKE CONCAT('%', #{query.batchNo}, '%')


        AND b.template_id = #{query.templateId}


        AND t.name LIKE CONCAT('%', #{query.templateName}, '%')


        AND b.redeem_rule_type = #{query.redeemRuleType}


        AND b.validity_type = #{query.validityType}


        AND b.status = #{query.status}


        AND b.create_time >= #{query.startTime}


        AND b.create_time <= #{query.endTime}


ORDER BY b.create_time DESC, b.id DESC

mapper.update:
UPDATE coupon_activation_batch
SET status      = #{status},
    update_time = #{updateTime},
    update_by   = #{operatorId}
WHERE id = #{batchId}
  AND is_deleted = 0

UPDATE coupon_activation_batch
SET is_deleted  = 1,
    update_time = #{updateTime},
    update_by   = #{operatorId}
WHERE id = #{batchId}
  AND is_deleted = 0
